mapper.select:
SELECT * FROM (
    SELECT *,
        (6371 * acos(
            cos(radians(#{latitude})) * cos(radians(destination_lat)) *
            cos(radians(destination_lng) - radians(#{longitude})) +
            sin(radians(#{latitude})) * sin(radians(destination_lat))
        )) AS distance
    FROM trips
    WHERE visibility = 'PUBLIC'
      AND is_deleted = FALSE
      AND destination_lat IS NOT NULL
      AND destination_lng IS NOT NULL
      
          AND owner_id != #{excludeUserId,javaType=java.util.UUID,jdbcType=OTHER}
          AND id NOT IN (
              SELECT trip_id FROM trip_members 
              WHERE user_id = #{excludeUserId,javaType=java.util.UUID,jdbcType=OTHER}
              AND status = 'ACCEPTED'
          )
      
      
          AND LOWER(destination) LIKE LOWER(CONCAT('%', #{destination}, '%'))
      
) AS t
WHERE distance <= #{radiusKm}
ORDER BY distance ASC
LIMIT #{limit} OFFSET #{offset}
